   function automatic esr_spdmctrl_t write_spdmctrl;
   input [$bits(esr_spdmctrl_t)-1:0] d;
   esr_spdmctrl_t dd;
   esr_spdmctrl_t ret;
   begin
      dd = esr_spdmctrl_t'(d);
      ret.reserved0 = 'x; // RO field... needs to be set manually if used
      ret.ndmreset = dd.ndmreset;
      ret.clrresethaltreq = dd.clrresethaltreq;
      ret.setresethaltreq = dd.setresethaltreq;
      ret.reserved1 = 'x; // RO field... needs to be set manually if used
      ret.ackhavereset = dd.ackhavereset;
      ret.hartreset = dd.hartreset;
      ret.resumereq = dd.resumereq;
      ret.haltreq = dd.haltreq;
      ret.reserved2 = 'x; // RO field... needs to be set manually if used
      return ret;
   end
   endfunction

   //conversion functions for esr_sphastatus_t
   function automatic esr_sphastatus_t write_sphastatus;
   input [$bits(esr_sphastatus_t)-1:0] d;
   esr_sphastatus_t dd;
   esr_sphastatus_t ret;
   begin
      dd = esr_sphastatus_t'(d);
      ret.halted = 'x; // RO field... needs to be set manually if used
      ret.running = 'x; // RO field... needs to be set manually if used
      ret.resumeack = 'x; // RO field... needs to be set manually if used
      ret.havereset = 'x; // RO field... needs to be set manually if used
      ret.busy = 'x; // RO field... needs to be set manually if used
      ret.exception = dd.exception;
      ret.error = dd.error;
      ret.reserved = dd.reserved;
      return ret;
   end
   endfunction
